defmodule BtcTxFeed.TxParserDecodePolicyTest do
  # async: false because Application.put_env is global state
  use ExUnit.Case, async: false

  alias BtcTxFeed.TxParser

  # SegWit V1: 2 inputs, 2 P2WPKH outputs — used to trigger max_vin_count
  @segwit_v1_hex ""

  # Legacy V1: 1 input, 33 P2PKH outputs — used to trigger max_vout_count
  @legacy_v1_hex ""

  defp raw(hex), do: Base.decode16!(hex, case: :lower)

  defp with_policy(overrides) do
    original = Application.get_env(:btc_tx_feed, :decode_policy)
    Application.put_env(:btc_tx_feed, :decode_policy, overrides)
    on_exit(fn -> Application.put_env(:btc_tx_feed, :decode_policy, original) end)
  end

  describe "parse/1 decode policy enforcement" do
    test "rejects transaction when input count exceeds max_vin_count" do
      # @segwit_v1_hex has 2 inputs; limit to 1
      with_policy(max_vin_count: 1)
      assert {:error, _} = TxParser.parse(raw(@segwit_v1_hex))
    end

    test "rejects transaction when output count exceeds max_vout_count" do
      # @legacy_v1_hex has 33 outputs; limit to 5
      with_policy(max_vout_count: 5)
      assert {:error, _} = TxParser.parse(raw(@legacy_v1_hex))
    end

    test "accepts transaction when limits are set but not exceeded" do
      with_policy(max_vin_count: 10, max_vout_count: 50)
      assert {:ok, _} = TxParser.parse(raw(@legacy_v1_hex))
    end
  end
end
